RANGE.executor_code:
def executor(payload, progress_cb):
    start = int(payload.get("start", 1))
    end = int(payload.get("end", 100))

    if start > end:
        start, end = end, start

    total = 0
    count = end - start + 1
    report_every = max(1, count // 10)

    for idx, value in enumerate(range(start, end + 1), start=1):
        total += value
        if idx % report_every == 0 or idx == count:
            progress_cb(idx / count)

    return {
        "status": "success",
        "partial_sum": total,
        "count": count,
        "start": start,
        "end": end
    }

Prime check.executor_code:
def executor(payload, progress_cb):
    numbers = payload.get("data", [])

    def is_prime(n: int) -> bool:
        if n < 2:
            return False
        if n in (2, 3):
            return True
        if n % 2 == 0:
            return False
        i = 3
        limit = int(n ** 0.5) + 1
        while i <= limit:
            if n % i == 0:
                return False
            i += 2
        return True

    primes = []
    total = len(numbers) if numbers else 1

    for idx, value in enumerate(numbers, start=1):
        try:
            n = int(value)
            if is_prime(n):
                primes.append(n)
        except Exception:
            pass

        if idx % max(1, total // 10) == 0 or idx == total:
            progress_cb(idx / total)

    return {
        "status": "success",
        "input_count": len(numbers),
        "prime_count": len(primes),
        "primes": primes
    }

price_prediction.executor_code:
def executor(payload, progress_cb):
    import csv

    dataset_files = payload.get("dataset_files", [])
    epochs = int(payload.get("epochs", 200))
    lr = float(payload.get("lr", 1e-6))

    if not dataset_files:
        return {"status": "error", "message": "No dataset_files provided"}

    xs, ys = [], []
    for file_path in dataset_files:
        with open(file_path, "r") as f:
            reader = csv.DictReader(f)
            for row in reader:
                xs.append(float(row["size"]))
                ys.append(float(row["price"]))

    if not xs:
        return {"status": "error", "message": "Dataset is empty"}

    w, b = 0.0, 0.0
    n = len(xs)

    for epoch in range(1, epochs + 1):
        dw, db = 0.0, 0.0
        for x, y in zip(xs, ys):
            pred = w * x + b
            err = pred - y
            dw += (2 / n) * err * x
            db += (2 / n) * err

        w -= lr * dw
        b -= lr * db

        if epoch % max(1, epochs // 10) == 0:
            progress_cb(epoch / epochs)

    mse = sum((w * x + b - y) ** 2 for x, y in zip(xs, ys)) / n

    return {
        "status": "success",
        "samples": n,
        "w": w,
        "b": b,
        "mse": mse
    }

price_prediction.aggregator_code:
def aggregator(results):
    if not results:
        return {"status": "error", "message": "No results"}

    w_sum, b_sum, mse_sum, n = 0.0, 0.0, 0.0, 0
    for r in results:
        if r.get("status") == "success":
            w_sum += r.get("w", 0.0)
            b_sum += r.get("b", 0.0)
            mse_sum += r.get("mse", 0.0)
            n += 1

    if n == 0:
        return {"status": "error", "message": "No successful results"}

    return {
        "task": "linear_regression",
        "avg_w": w_sum / n,
        "avg_b": b_sum / n,
        "avg_mse": mse_sum / n,
        "workers": n
    }
